"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import Navigation from "@/components/Navigation";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  CalendarDays,
  CheckCircle2,
  Clock,
  LogOut,
  MapPin,
  Phone,
  Mail,
  Sparkles,
} from "lucide-react";

const BOOKINGS_STORAGE_KEY = "customerBookings";

const defaultBookings = [
  {
    id: "CB-101",
    service: "Deep Cleaning",
    date: "2025-01-12",
    time: "09:00 AM",
    status: "scheduled",
    address: "123 Main St, Chicago, IL",
    contact: "(555) 123-4567",
    notes: "Focus on kitchen appliances.",
  },
  {
    id: "CB-102",
    service: "Standard Cleaning",
    date: "2025-01-19",
    time: "11:30 AM",
    status: "scheduled",
    address: "123 Main St, Chicago, IL",
    contact: "(555) 123-4567",
    notes: "Pet-friendly solutions.",
  },
  {
    id: "CB-099",
    service: "Move-Out Cleaning",
    date: "2024-12-15",
    time: "02:00 PM",
    status: "completed",
    address: "123 Main St, Chicago, IL",
    contact: "(555) 123-4567",
    notes: "Tenant inspection ready.",
  },
];

type Booking = typeof defaultBookings[number];

const CustomerDashboard = () => {
  const router = useRouter();
  const [customerName, setCustomerName] = useState("Customer");
  const [bookings, setBookings] = useState<Booking[]>(defaultBookings);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const isAuthenticated = localStorage.getItem("customerAuth") === "true";
    const accountRaw = localStorage.getItem("customerAccount");

    if (!isAuthenticated || !accountRaw) {
      router.replace("/login");
      return;
    }

    try {
      const account = JSON.parse(accountRaw) as { name?: string; email?: string };
      if (account?.name) {
        setCustomerName(account.name);
      }
    } catch {
      // ignore parsing errors and fallback to default name
    }

    const storedBookings = localStorage.getItem(BOOKINGS_STORAGE_KEY);
    if (storedBookings) {
      try {
        const parsed = JSON.parse(storedBookings) as Booking[];
        if (Array.isArray(parsed)) {
          setBookings(parsed);
        }
      } catch {
        localStorage.setItem(BOOKINGS_STORAGE_KEY, JSON.stringify(defaultBookings));
      }
    } else {
      localStorage.setItem(BOOKINGS_STORAGE_KEY, JSON.stringify(defaultBookings));
    }

    setLoading(false);
  }, [router]);

  const upcomingBookings = useMemo(() => {
    const today = new Date();
    return bookings
      .filter((booking) => new Date(booking.date) >= new Date(today.toDateString()))
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [bookings]);

  const completedCount = useMemo(
    () => bookings.filter((booking) => booking.status === "completed").length,
    [bookings]
  );

  const nextBooking = upcomingBookings[0] ?? null;

  const handleLogout = () => {
    if (typeof window === "undefined") return;
    localStorage.setItem("customerAuth", "false");
    router.replace("/login");
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-muted/40">
        <div className="flex flex-col items-center gap-3 text-muted-foreground">
          <Clock className="h-8 w-8 animate-spin" />
          <p>Loading your dashboard...</p>
        </div>
      </div>
    );
  }

  const firstName = customerName.split(" ")[0] || "Customer";

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5">
      <Navigation />
      <main className="container mx-auto px-4 pt-28 pb-16 space-y-10">
        <section className="bg-card border border-border rounded-3xl p-8 shadow-lg relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-br from-primary/10 via-transparent to-primary/5 opacity-60" />
          <div className="relative z-10 flex flex-col lg:flex-row items-start lg:items-center justify-between gap-6">
            <div>
              <p className="text-sm uppercase tracking-wider text-primary font-semibold flex items-center gap-2">
                <Sparkles className="h-4 w-4" /> Welcome back
              </p>
              <h1 className="text-3xl md:text-4xl font-bold mt-2">Hi {firstName}, your home is in good hands.</h1>
              <p className="text-muted-foreground mt-3 max-w-2xl">
                Track your upcoming services, review booking details, and schedule new cleanings—all from your personal dashboard.
              </p>
              <div className="mt-6 flex flex-wrap gap-3">
                <Button size="lg" asChild>
                  <Link href="/book-now">
                    Book a Service
                  </Link>
                </Button>
                <Button variant="outline" size="lg" onClick={handleLogout} className="gap-2">
                  <LogOut className="h-4 w-4" /> Sign Out
                </Button>
              </div>
            </div>
            {nextBooking && (
              <Card className="w-full max-w-sm border-primary/30">
                <CardHeader>
                  <CardTitle className="text-base flex items-center gap-2">
                    <CalendarDays className="h-4 w-4 text-primary" /> Next appointment
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-2 text-sm">
                  <p className="text-lg font-semibold">{nextBooking.service}</p>
                  <p className="text-muted-foreground flex items-center gap-2">
                    <Clock className="h-4 w-4" /> {nextBooking.date} • {nextBooking.time}
                  </p>
                  <p className="text-muted-foreground flex items-center gap-2">
                    <MapPin className="h-4 w-4" /> {nextBooking.address}
                  </p>
                  <div className="text-xs text-muted-foreground border border-dashed border-primary/40 rounded-lg p-3">
                    {nextBooking.notes}
                  </div>
                </CardContent>
              </Card>
            )}
          </div>
        </section>

        <section className="grid gap-4 md:grid-cols-3">
          <Card>
            <CardHeader>
              <CardTitle className="text-sm text-muted-foreground">Upcoming bookings</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-3xl font-bold">{upcomingBookings.length}</p>
              <p className="text-sm text-muted-foreground">Scheduled in the next 30 days</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader>
              <CardTitle className="text-sm text-muted-foreground">Completed services</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-3xl font-bold">{completedCount}</p>
              <p className="text-sm text-muted-foreground">Thanks for letting us serve you</p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader>
              <CardTitle className="text-sm text-muted-foreground">Loyalty perks</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-3xl font-bold">Gold</p>
              <p className="text-sm text-muted-foreground">Book 2 more services to unlock a free add-on</p>
            </CardContent>
          </Card>
        </section>

        <section className="grid gap-6 lg:grid-cols-3">
          <Card className="lg:col-span-2">
            <CardHeader className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
              <div>
                <CardTitle>Upcoming schedule</CardTitle>
                <p className="text-sm text-muted-foreground">Stay on top of what’s next</p>
              </div>
              <Button variant="outline" size="sm" asChild>
                <Link href="/book-now">Add booking</Link>
              </Button>
            </CardHeader>
            <CardContent className="space-y-4">
              {upcomingBookings.length === 0 && (
                <div className="text-center text-muted-foreground text-sm py-6">
                  No upcoming services. Schedule your next visit to keep things sparkling.
                </div>
              )}
              {upcomingBookings.map((booking) => (
                <div
                  key={booking.id}
                  className="border border-border rounded-xl p-4 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3"
                >
                  <div>
                    <p className="font-semibold">{booking.service}</p>
                    <p className="text-sm text-muted-foreground flex items-center gap-2">
                      <CalendarDays className="h-4 w-4" /> {booking.date} • {booking.time}
                    </p>
                    <p className="text-sm text-muted-foreground flex items-center gap-2">
                      <MapPin className="h-4 w-4" /> {booking.address}
                    </p>
                  </div>
                  <div className="text-sm text-muted-foreground">
                    <p className="flex items-center gap-2">
                      <Phone className="h-4 w-4" /> {booking.contact}
                    </p>
                    <p className="flex items-center gap-2">
                      <Mail className="h-4 w-4" /> support@premierpro.com
                    </p>
                  </div>
                  <Button variant="outline" size="sm" asChild>
                    <Link href={`/book-now?bookingId=${booking.id}`}>Manage</Link>
                  </Button>
                </div>
              ))}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Service history</CardTitle>
              <p className="text-sm text-muted-foreground">Your recent visits</p>
            </CardHeader>
            <CardContent className="space-y-4">
              {bookings
                .filter((booking) => booking.status === "completed")
                .slice(0, 3)
                .map((booking) => (
                  <div key={booking.id} className="border border-border rounded-xl p-3">
                    <p className="font-semibold flex items-center gap-2">
                      <CheckCircle2 className="h-4 w-4 text-green-500" /> {booking.service}
                    </p>
                    <p className="text-xs text-muted-foreground flex items-center gap-1">
                      <CalendarDays className="h-3 w-3" /> {booking.date}
                    </p>
                    <p className="text-xs text-muted-foreground mt-2">{booking.notes}</p>
                  </div>
                ))}
              {completedCount === 0 && (
                <p className="text-sm text-muted-foreground">
                  Your completed cleanings will appear here once a service is finished.
                </p>
              )}
            </CardContent>
          </Card>
        </section>
      </main>
    </div>
  );
};

export default CustomerDashboard;
